<script setup>import {onMounted,ref} from 'vue';import {useRoute} from 'vue-router';import {getMyTradeIn,respondTradeIn} from '../api/tradeInApi';import ConfirmModal from '../components/ConfirmModal.vue';const route=useRoute(),item=ref(null),loading=ref(true),busy=ref(false),error=ref(''),success=ref(''),action=ref(null);const money=v=>v==null?'尚未報價':new Intl.NumberFormat('zh-TW',{style:'currency',currency:'TWD',maximumFractionDigits:0}).format(v);async function respond(){busy.value=true;try{item.value=await respondTradeIn(item.value.id,action.value==='accept');success.value=action.value==='accept'?'已接受報價。':'已婉拒報價。';action.value=null}catch(e){error.value=e.message}finally{busy.value=false}}onMounted(async()=>{try{item.value=await getMyTradeIn(route.params.id)}catch(e){error.value=e.message}finally{loading.value=false}})</script>
<template><section class="member-section"><RouterLink class="back-link" to="/member/trade-ins">← 返回我的收購</RouterLink><p v-if="error" class="alert alert-error">{{error}}</p><p v-if="success" class="alert alert-success">{{success}}</p><div v-if="loading" class="loading-state">正在載入申請…</div><template v-else-if="item"><div class="page-heading"><div><span class="eyebrow">TRADE-IN DETAIL</span><h1>{{item.tradeInNumber}}</h1><p>{{item.brand}} {{item.model}} · {{item.storageCapacity}}</p></div><span class="badge">{{item.status}}</span></div><div class="detail-cards"><section class="card"><h2>裝置資訊</h2><dl><dt>外觀狀況</dt><dd>{{item.appearanceCondition}}</dd><dt>功能狀況</dt><dd>{{item.functionCondition}}</dd><dt>顏色</dt><dd>{{item.color||'未提供'}}</dd><dt>補充說明</dt><dd>{{item.description||'無'}}</dd></dl></section><section class="card quote-card"><h2>平台報價</h2><strong class="quote-price">{{money(item.quotedPrice)}}</strong><p v-if="item.rejectionReason">說明：{{item.rejectionReason}}</p><div v-if="item.status==='QUOTED'" class="success-actions"><button class="button button-primary" @click="action='accept'">接受報價</button><button class="button button-ghost" @click="action='reject'">婉拒報價</button></div></section></div></template><ConfirmModal :open="Boolean(action)" :title="action==='accept'?'接受報價':'婉拒報價'" :message="action==='accept'?'確定接受平台報價嗎？':'確定婉拒本次報價嗎？'" :busy="busy" @cancel="action=null" @confirm="respond"/></section></template>
